var MODELS = {
  primary: [
    "meta-llama/llama-4-scout-17b-16e-instruct",
    "llama-3.3-70b-versatile"
  ],
  fallback: "llama-3.1-8b-instant"
};
var requestCounter = 0;
function buildUserMessage(input, result2) {
  return JSON.stringify({
    name: input.name,
    role: input.role,
    experience: input.experience,
    description: input.description,
    technologies: input.technologies,
    assignedModel: result2.model.name,
    modelKey: result2.model.key,
    score: result2.score,
    daysLeft: result2.daysLeft,
    tier: result2.tier
  });
}
function isRateLimited(err) {
  return err instanceof Error && "status" in err && err.status === 429;
}
async function callGroq(client2, model, userMessage) {
  const response = await client2.chat.completions.create({
    model,
    messages: [
      { role: "system", content: ANALYZER_SYSTEM_PROMPT },
      { role: "user", content: userMessage }
    ],
    temperature: 0.9,
    max_tokens: 800,
    response_format: { type: "json_object" }
  });
  const text2 = response.choices[0]?.message?.content || "";
  return JSON.parse(text2);
}
function generatedByLabel(model) {
  if (model.includes("scout")) return "groq-scout";
  if (model.includes("70b")) return "groq-70b";
  return "groq-8b";
}
async function generateHumorContent(input, scoringResult, lang = "en", gender = "other") {
  const apiKey = process.env.GROQ_API_KEY;
  if (!apiKey) {
    const content2 = generateLocalFallback(
      input,
      scoringResult.model.key,
      lang,
      gender
    );
    return { content: content2, generatedBy: "local-fallback" };
  }
  const client2 = new OpenAI({
    baseURL: "https://api.groq.com/openai/v1",
    apiKey
  });
  const userMessage = buildUserMessage(input, scoringResult);
  const primaryIndex = requestCounter % MODELS.primary.length;
  requestCounter++;
  const orderedPrimaries = [
    MODELS.primary[primaryIndex],
    MODELS.primary[(primaryIndex + 1) % MODELS.primary.length]
  ];
  for (const model of orderedPrimaries) {
    try {
      const content2 = await callGroq(client2, model, userMessage);
      return { content: content2, generatedBy: generatedByLabel(model) };
    } catch (err) {
      if (!isRateLimited(err)) throw err;
    }
  }
  try {
    const content2 = await callGroq(client2, MODELS.fallback, userMessage);
    return { content: content2, generatedBy: "groq-8b" };
  } catch (err) {
    if (!isRateLimited(err)) throw err;
  }
  const content = generateLocalFallback(input, scoringResult.model.key, lang, gender);
  return { content, generatedBy: "local-fallback" };
}

