// packages/api/src/routes/leaderboard.ts
var leaderboard = new Hono2();
var VALID_SORTS = ["highest", "lowest", "recent"];
var MAX_LIMIT = 50;
var DEFAULT_LIMIT = 20;
leaderboard.get("/api/leaderboard", async (c) => {
  const sortParam = c.req.query("sort") ?? "highest";
  const limitParam = c.req.query("limit");
  const offsetParam = c.req.query("offset");
  const sort = VALID_SORTS.includes(sortParam) ? sortParam : "highest";
  const limit2 = Math.min(
    Math.max(1, parseInt(limitParam ?? "", 10) || DEFAULT_LIMIT),
    MAX_LIMIT
  );
  const offset = Math.max(0, parseInt(offsetParam ?? "", 10) || 0);
  const { entries, total } = await getLeaderboard(sort, limit2, offset);
  return c.json({
    entries: entries.map((e) => ({
      id: e.id,
      name: e.name,
      role: e.role,
      score: e.score,
      modelKey: e.modelKey,
      modelName: e.modelName,
      daysLeft: e.daysLeft,
      createdAt: e.createdAt
    })),
    total,
    hasMore: offset + limit2 < total
  });
});

