function getBaseUrl(c) {
  const url2 = new URL(c.req.url);
  return `${url2.protocol}//${url2.host}`;
}
function formatDays(days) {
  if (days >= 99999) return "\u221E";
  if (days >= 365) {
    const years = Math.floor(days / 365);
    return `${years.toLocaleString("he-IL")} \u05E9\u05E0\u05D9\u05DD`;
  }
  return `${days.toLocaleString("he-IL")} \u05D9\u05DE\u05D9\u05DD`;
}
function escapeHtml(str2) {
  return str2.replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;").replace(/"/g, "&quot;");
}
function escapeAttr(str2) {
  return str2.replace(/&/g, "&amp;").replace(/"/g, "&quot;").replace(/</g, "&lt;").replace(/>/g, "&gt;");
}
